import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/applications.css';

const STATUS_CONFIG = {
  pending:    { label: 'Pending',    icon: '⏳', color: 'warning' },
  reviewing:  { label: 'Reviewing',  icon: '🔍', color: 'info' },
  accepted:   { label: 'Accepted',   icon: '✅', color: 'success' },
  rejected:   { label: 'Rejected',   icon: '❌', color: 'error' },
};

const MyApplications = () => {
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    fetchApplications();
  }, []);

  const fetchApplications = async () => {
    setLoading(true);
    try {
      const res = await axios.get('/api/applications/user');
      setApplications(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const filtered = filter === 'all'
    ? applications
    : applications.filter(a => a.status === filter);

  const counts = {
    all: applications.length,
    pending: applications.filter(a => a.status === 'pending').length,
    reviewing: applications.filter(a => a.status === 'reviewing').length,
    accepted: applications.filter(a => a.status === 'accepted').length,
    rejected: applications.filter(a => a.status === 'rejected').length,
  };

  return (
    <div className="applications-page page-content">
      {/* Header */}
      <div className="apps-header">
        <div className="container">
          <h1 className="apps-title">My Applications</h1>
          <p className="apps-subtitle">Track the status of all your job applications</p>

          {/* Stats */}
          <div className="apps-stats">
            {Object.entries(STATUS_CONFIG).map(([key, cfg]) => (
              <div key={key} className={`app-stat app-stat-${cfg.color}`}>
                <span className="app-stat-icon">{cfg.icon}</span>
                <div>
                  <div className="app-stat-value">{counts[key] || 0}</div>
                  <div className="app-stat-label">{cfg.label}</div>
                </div>
              </div>
            ))}
          </div>

          {/* Filter Tabs */}
          <div className="apps-filter-tabs">
            {['all', 'pending', 'reviewing', 'accepted', 'rejected'].map(tab => (
              <button
                key={tab}
                className={`apps-tab ${filter === tab ? 'active' : ''}`}
                onClick={() => setFilter(tab)}
              >
                {tab.charAt(0).toUpperCase() + tab.slice(1)}
                <span className="tab-count">{counts[tab]}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="container apps-content">
        {loading ? (
          <div className="apps-list">
            {[1,2,3].map(i => <div key={i} className="app-card-skeleton" />)}
          </div>
        ) : filtered.length === 0 ? (
          <div className="apps-empty">
            <div>📋</div>
            <h3>{filter === 'all' ? "No applications yet" : `No ${filter} applications`}</h3>
            <p>{filter === 'all'
              ? "Start applying to jobs and they'll appear here."
              : `You have no ${filter} applications at the moment.`}</p>
          </div>
        ) : (
          <div className="apps-list">
            {filtered.map((app) => {
              const cfg = STATUS_CONFIG[app.status] || STATUS_CONFIG.pending;
              const job = app.job;
              return (
                <div key={app._id} className="app-card">
                  <div className="app-card-left">
                    <div className="app-company-avatar">
                      {job?.companyName?.charAt(0) || '?'}
                    </div>
                  </div>
                  <div className="app-card-body">
                    <div className="app-card-top">
                      <div>
                        <h3 className="app-job-title">{job?.title || 'Job Removed'}</h3>
                        <p className="app-company">{job?.companyName || '—'}</p>
                      </div>
                      <div className={`app-status-chip app-status-${cfg.color}`}>
                        {cfg.icon} {cfg.label}
                      </div>
                    </div>
                    <div className="app-meta">
                      {job?.location && <span>📍 {job.location}</span>}
                      {job?.type && (
                        <span className={`badge ${job.type === 'Internship' ? 'badge-internship' : 'badge-job'}`}>
                          {job.type}
                        </span>
                      )}
                      {job?.salary && <span>💰 {job.salary}</span>}
                    </div>
                    <div className="app-card-bottom">
                      <span className="app-date">
                        Applied on {new Date(app.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}
                      </span>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyApplications;
